import { useState, useEffect } from 'react'
import { BookmarkIcon, TrashIcon } from '@heroicons/react/24/outline'
import { useAuth } from '../context/AuthContext'

// Mock data for saved articles - in production, this would come from an API
const mockSavedArticles = [
  {
    id: 1,
    headline: "Global Markets Rally as Economic Indicators Show Strong Growth",
    subtitle: "Investors celebrate as major indices reach new heights",
    category: "Economics",
    image: "https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=800&h=600&fit=crop",
    savedDate: "2024-01-15"
  },
  {
    id: 2,
    headline: "Championship Final Set for Next Weekend",
    subtitle: "Top teams prepare for the ultimate showdown",
    category: "Sports",
    image: "https://images.unsplash.com/photo-1574629810360-7efbbe195018?w=800&h=600&fit=crop",
    savedDate: "2024-01-14"
  },
  {
    id: 3,
    headline: "New Film Breaks Box Office Records",
    subtitle: "Audiences flock to theaters for latest blockbuster",
    category: "Entertainment",
    image: "https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=800&h=600&fit=crop",
    savedDate: "2024-01-13"
  },
]

const categoryColors = {
  "Sports": "bg-red-100 text-red-700",
  "International": "bg-blue-100 text-blue-700",
  "Economics": "bg-green-100 text-green-700",
  "Entertainment": "bg-purple-100 text-purple-700",
  "Technology": "bg-indigo-100 text-indigo-700",
  "Science": "bg-cyan-100 text-cyan-700",
  "Culture": "bg-amber-100 text-amber-700",
  "Lifestyle": "bg-pink-100 text-pink-700",
  "Local": "bg-teal-100 text-teal-700",
}

export default function ClippingsPage() {
  const { user, isAuthenticated } = useAuth()
  const [savedArticles, setSavedArticles] = useState([])

  useEffect(() => {
    // In production, fetch saved articles from API
    // For now, use mock data regardless of authentication
    setSavedArticles(mockSavedArticles)
  }, [])

  const handleRemoveArticle = (articleId) => {
    setSavedArticles(savedArticles.filter(article => article.id !== articleId))
    // In production, make API call to remove article
  }

  const formatDate = (dateString) => {
    const date = new Date(dateString)
    return date.toLocaleDateString('en-US', { 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    })
  }

  return (
    <div className="isolate bg-cream-50 px-8 py-28 sm:py-36 lg:px-10 min-h-screen">
      <div className="mx-auto max-w-7xl">
        {/* Header Section */}
        <div className="mx-auto max-w-3xl text-center mb-12">
          <h1 className="text-balance text-4xl font-serif font-normal tracking-tight text-soft-blue-800 sm:text-5xl">
            your clippings
          </h1>
          <p className="mt-6 text-sm text-soft-blue-600">
            articles you've saved for later reading
          </p>
        </div>

        {/* Articles Grid */}
        {savedArticles.length > 0 ? (
          <div className="columns-1 sm:columns-2 lg:columns-4 gap-6 space-y-6">
            {savedArticles.map((article) => (
              <div
                key={article.id}
                className="break-inside-avoid rounded-2xl border border-soft-blue-200 bg-white overflow-hidden shadow-sm hover:shadow-md transition-shadow group"
              >
                {/* Image */}
                <div className="relative aspect-[4/3] overflow-hidden">
                  <img
                    src={article.image}
                    alt={article.headline}
                    className="w-full h-full object-cover grayscale group-hover:grayscale-0 group-hover:scale-105 transition duration-300"
                  />
                  {/* Gradient overlay */}
                  <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/20 to-transparent"></div>

                  {/* Category Badge */}
                  <div className="absolute top-4 left-4">
                    <span className={`inline-flex items-center rounded-full px-3 py-1 text-xs font-medium ${
                      categoryColors[article.category] || "bg-gray-100 text-gray-700"
                    }`}>
                      {article.category}
                    </span>
                  </div>

                  {/* Remove Button */}
                  <button
                    onClick={() => handleRemoveArticle(article.id)}
                    className="absolute top-4 right-4 p-2 rounded-full bg-white/90 hover:bg-white text-soft-blue-700 hover:text-red-600 transition-colors"
                    aria-label="Remove article"
                  >
                    <TrashIcon className="h-5 w-5" />
                  </button>
                </div>

                {/* Content */}
                <div className="p-5">
                  <h3 className="text-lg font-serif font-semibold text-soft-blue-800">
                    {article.headline}
                  </h3>
                  <p className="text-sm text-soft-blue-600 mt-2">
                    {article.subtitle}
                  </p>
                  <p className="text-xs text-soft-blue-500 mt-3">
                    Saved on {formatDate(article.savedDate)}
                  </p>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="text-center py-16">
            <BookmarkIcon className="mx-auto h-16 w-16 text-soft-blue-300" />
            <h3 className="mt-6 text-2xl font-serif font-normal text-soft-blue-800">
              no clippings yet
            </h3>
            <p className="mt-3 text-sm text-soft-blue-600">
              start saving articles from the newsstand to see them here.
            </p>
          </div>
        )}
      </div>
    </div>
  )
}
